alter table public.profiles enable row level security; alter table public.products enable row level security; alter table public.components enable row level security; alter table public.bom enable row level security; alter table public.inventory_baselines enable row level security; alter table public.inventory_baseline_items enable row level security; alter table public.inventory_events enable row level security; alter table public.inventory_event_lines enable row level security;
create function public.current_role() returns app_role language sql stable security definer set search_path=public as $$select role from profiles where id=auth.uid()$$;
create policy "read authenticated" on products for select to authenticated using(true); create policy "read authenticated" on components for select to authenticated using(true); create policy "read authenticated" on bom for select to authenticated using(true); create policy "read authenticated" on inventory_events for select to authenticated using(true); create policy "read authenticated" on inventory_event_lines for select to authenticated using(true); create policy "read authenticated" on inventory_baselines for select to authenticated using(true); create policy "read authenticated" on inventory_baseline_items for select to authenticated using(true);
create policy "admin products" on products for all to authenticated using(current_role()='admin') with check(current_role()='admin'); create policy "admin components" on components for all to authenticated using(current_role()='admin') with check(current_role()='admin'); create policy "admin bom" on bom for all to authenticated using(current_role()='admin') with check(current_role()='admin');
-- Only allow operational writes through SECURITY INVOKER RPC functions; do not grant direct INSERT/UPDATE/DELETE on event tables.
grant execute on function public.report_window_production(text,numeric,text,boolean) to authenticated;
